import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(from_pos, to_pos):
        return np.linalg.norm(to_pos - from_pos) / truck_speed

    def time_window_compliance_penalty(arrive_time, window):
        if arrive_time > window[1]:
            return np.inf  # Missed the time window completely
        elif arrive_time < window[0]:
            return window[0] - arrive_time  # Needs to wait for the window to open
        return 0  # Arrives within the window

    travel_costs = np.array([travel_time(cur_truck_pos, customer) for customer in unvisited_customers])
    penalties = np.array([time_window_compliance_penalty(current_time + travel_costs[i], tw) for i, tw in enumerate(time_windows)])
    total_costs = travel_costs + penalties

    # DPC Adjustment based on other trucks' states
    coordination_adjustment = np.zeros(len(unvisited_customers))

    for i, cust in enumerate(unvisited_customers):
        for pos in all_truck_pos:
            if not np.array_equal(pos, cur_truck_pos):
                # Check how other trucks affect the decision
                other_travel_time = travel_time(pos, cust)
                impact = time_window_compliance_penalty(current_time + other_travel_time, time_windows[i])
                coordination_adjustment[i] += impact  # Increasing the coordination complexity

    # Incorporating dynamic path coordination adjustments
    final_scores = total_costs - 0.1 * coordination_adjustment  # Smaller adjustment impact
    best_node = np.argmin(final_scores)

    return best_node
